mapper.select:
SELECT ID AS id, TYPE_NAME AS typeName, PARENT_ID AS parentId, CATEGORY_LEVEL AS categoryLevel, SORT_ORDER AS sortOrder, CREATE_TIME AS createTime FROM E_M_EQPT_TYPE WHERE DEL_FLAG = 0 AND CATEGORY_LEVEL <= 3
AND TYPE_NAME LIKE #{kwLike}
ORDER BY NVL(SORT_ORDER,0), CREATE_TIME DESC

SELECT ID, TYPE_NAME, decode(CATEGORY_LEVEL,3,null,PARENT_ID) PARENT_ID, CATEGORY_LEVEL, SORT_ORDER, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, DEL_FLAG, DELETE_BY, DELETE_BY_NAME, DELETE_TIME FROM E_M_EQPT_TYPE WHERE DEL_FLAG = 0 and CATEGORY_LEVEL > 2
and TYPE_NAME like #{typeNameLike}
ORDER BY SORT_ORDER ASC, CATEGORY_LEVEL ASC, CREATE_TIME ASC

SELECT COUNT(*)
FROM E_M_EQPT_TYPE
WHERE TYPE_NAME = #{typeName}
AND DEL_FLAG = 0

    AND PARENT_ID = #{parentId}


    AND (PARENT_ID IS NULL OR PARENT_ID = 0)


    AND ID != #{id}

SELECT ID, TYPE_NAME, PARENT_ID, CATEGORY_LEVEL, SORT_ORDER, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, DEL_FLAG, DELETE_BY, DELETE_BY_NAME, DELETE_TIME FROM E_M_EQPT_TYPE WHERE DEL_FLAG = 0 AND CATEGORY_LEVEL = #{categoryLevel}
AND PARENT_ID = #{parentId}
AND (PARENT_ID IS NULL OR PARENT_ID = 0)
ORDER BY SORT_ORDER ASC, CREATE_TIME ASC
